            bp = '(.{%d})(%s)(%s)(.{%d})' % (pre, piece, tgt, post)
            gb, db = '\\1\\2\\3\\4', '\\1_%s\\4' % new_piece
            cg, eg = 5, 6
    else:
        pre, post = dst, 63 - src
